+import { $internal } from '../../common';
+import type { Entity } from '../../entity/types';
+import type { RelationPair } from '../../relation/types';
+import type { TraitInstance } from '../../trait/types';
+import type { World } from '../../world';
+import type { PairTrackingGroup, QueryInstance } from '../types';
+
+function keyForPair(pair: RelationPair, target: Entity): string {
+    return `${pair[$internal].relation[$internal].trait.id}:${target}`;
+}
+
+function matches(pair: RelationPair, relationTraitId: number, target: Entity): boolean {
+    const ctx = pair[$internal];
+    return (
+        ctx.relation[$internal].trait.id === relationTraitId &&
+        (ctx.target === '*' || ctx.target === target)
+    );
+}
+
+function groupMatches(group: PairTrackingGroup, eid: number): boolean {
+    const events = group.trackers.get(eid);
+    if (!events?.size) return false;
+
+    if (group.logic === 'or') return true;
+
+    for (const pair of group.pairs) {
+        const prefix = `${pair[$internal].relation[$internal].trait.id}:`;
+        if (pair[$internal].target === '*') {
+            let found = false;
+            for (const key of events.keys()) {
+                if (key.startsWith(prefix)) {
+                    found = true;
+                    break;
+                }
+            }
+            if (!found) return false;
+        } else if (!events.has(keyForPair(pair, pair[$internal].target))) {
+            return false;
+        }
+    }
+    return true;
+}
+
+/** Whether all target-specific tracking constraints currently match for an entity. */
+export function hasPairTrackingMatches(query: QueryInstance, entity: Entity): boolean {
+    if (!query.pairTrackingGroups.length) return true;
+    const eid = entity as number;
+
+    let hasOrGroup = false;
+    let anyOrMatched = false;
+    for (const group of query.pairTrackingGroups) {
+        const matches = groupMatches(group, eid);
+        if (group.logic === 'or') {
+            hasOrGroup = true;
+            anyOrMatched ||= matches;
+        } else if (!matches) {
+            return false;
+        }
+    }
+    return !hasOrGroup || anyOrMatched;
+}
+
+/** Record a target-specific event and update all tracking queries for that relation. */
+export function processPairTrackingEvent(
+    world: World,
+    instance: TraitInstance,
+    entity: Entity,
+    eventType: 'add' | 'remove' | 'change',
+    target: Entity
+): void {
+    const relationTraitId = instance.trait.id;
+    const eid = entity as number;
+
+    for (const query of instance.trackingQueries) {
+        let affected = false;
+        for (const group of query.pairTrackingGroups) {
+            let matched = false;
+            for (const pair of group.pairs) {
+                if (!matches(pair, relationTraitId, target)) continue;
+                matched = true;
+                const key = keyForPair(pair, target);
+                let events = group.trackers.get(eid);
+                if (!events) group.trackers.set(eid, (events = new Map()));
+
+                if (group.type === eventType) {
+                    events.set(key, target);
+                    let targets = query.pairEventTargets.get(eid);
+                    if (!targets) query.pairEventTargets.set(eid, (targets = new Map()));
+                    targets.set(relationTraitId, target);
+                } else {
+                    // Opposite events in one observation window cancel for this exact pair.
+                    events.delete(key);
+                }
+            }
+            affected ||= matched;
+        }
+
+        if (!affected) continue;
+        const { generationId, bitflag } = instance;
+        const match = query.checkTracking(world, entity, eventType, generationId, bitflag);
+        if (match) query.add(entity);
+        else query.remove(world, entity);
+    }
+}
+
+export function resetPairTracking(query: QueryInstance, eid: number): void {
+    for (const group of query.pairTrackingGroups) group.trackers.delete(eid);
+    query.pairEventTargets.delete(eid);
+}
