+import { $internal } from '../../common';
+import type { Relation } from '../../relation/types';
+import { isRelationPair } from '../../relation/utils/is-relation';
+import type { Trait } from '../../trait/types';
+import { isModifier } from '../modifier';
+import type { QueryHash, QueryParameter } from '../types';
+
+/**
+ * Include relation targets in modifier keys as well as ordinary relation filters.
+ * String tokens avoid collisions between trait IDs, modifier IDs, and entity IDs.
+ */
+export const createQueryHash = (parameters: QueryParameter[]): QueryHash => {
+    const values: string[] = [];
+    for (const param of parameters) {
+        if (isRelationPair(param)) {
+            const pair = param[$internal];
+            values.push(`r:${pair.relation[$internal].trait.id}:${pair.target}`);
+        } else if (isModifier(param)) {
+            for (const traitId of param.traitIds) values.push(`m:${param.id}:${traitId}`);
+            for (const pair of param.pairs) {
+                const ctx = pair[$internal];
+                values.push(`p:${param.id}:${ctx.relation[$internal].trait.id}:${ctx.target}`);
+            }
+        } else {
+            values.push(`t:${(param as Trait).id}`);
+        }
+    }
+    values.sort();
+    return values.join(',');
+};
